/*
 * ajax.js
 * https://github.com/savetheinternet/Tinyboard/blob/master/js/ajax.js
 *
 * Released under the MIT license
 * Copyright (c) 2013 Michael Save <savetheinternet@tinyboard.org>
 * Copyright (c) 2013-2014 Marcin Łabanowski <marcin@6irc.net>
 *
 * Usage:
 *   $config['additional_javascript'][] = 'js/jquery.min.js';
 *   $config['additional_javascript'][] = 'js/ajax.js';
 *
 */

$(window).ready(function() {
	var settings = new script_settings('ajax');
	var do_not_ajax = false;
	var csrfRefreshRequest = null;

	var extractAjaxErrorMessage = function(xhr) {
		if (xhr && xhr.responseJSON && xhr.responseJSON.error) {
			return xhr.responseJSON.error;
		}

		if (xhr && typeof xhr.responseText === 'string' && xhr.responseText.length) {
			try {
				var parsed = JSON.parse(xhr.responseText);
				if (parsed && parsed.error) {
					return parsed.error;
				}
			} catch (_error) {
			}
		}

		return null;
	};

	var currentCsrfToken = function() {
		var meta = document.querySelector('meta[name="csrf-token"]');
		if (meta && meta.content) {
			return meta.content;
		}

		var field = document.querySelector('input[name="_csrf_token"]');
		return field ? field.value : '';
	};

	var applyCsrfToken = function(token) {
		if (!token) {
			return;
		}

		var meta = document.querySelector('meta[name="csrf-token"]');

		if (meta) {
			meta.setAttribute('content', token);
		}

		$('input[name="_csrf_token"]').val(token);
	};

	var refreshCsrfToken = function() {
		if (csrfRefreshRequest) {
			return csrfRefreshRequest;
		}

		csrfRefreshRequest = $.getJSON('/csrf-token')
			.then(function(response) {
				var token = response && response.csrf_token;

				if (!token) {
					return $.Deferred().reject().promise();
				}

				applyCsrfToken(token);
				return token;
			})
			.always(function() {
				csrfRefreshRequest = null;
			});

		return csrfRefreshRequest;
	};

	// Enable submit button if disabled (cache problem)
	$('input[type="submit"]').removeAttr('disabled');
	
	var handle_form_submit = function() {
			if (do_not_ajax)
				return true;
			var form = this;
			var $wrappedForm = $(form);
			var $submit = $(form).find('input[type="submit"]');
			var submit_txt = $(this).find('input[type="submit"]').val();
			var is_reply_form = $(form).find('input[name="thread_id"], input[name="thread"]').length > 0;
			if (window.FormData === undefined)
				return true;
			if ($wrappedForm.data('ajax-posting')) {
				return false;
			}

			var resetSubmit = function() {
				$wrappedForm.removeData('ajax-posting');
				$submit.val(submit_txt);
				$submit.removeAttr('disabled');
			};

			var triggerAjaxAfterPost = function(post_response) {
				try {
					if (window.EirinchanFrontend && typeof window.EirinchanFrontend.dispatchAjaxAfterPostSuccess === 'function') {
						window.EirinchanFrontend.dispatchAjaxAfterPostSuccess(post_response, form);
					} else {
						$(document).trigger('ajax_after_post', [post_response, form]);
					}
				} catch (e) {
					console.error(e);
				}
			};

			var syncSeenForReply = function(post_response) {
				if (!is_reply_form || typeof window.markWatchedThreadSeen !== 'function') {
					return;
				}

				var threadId = parseInt($(form).find('input[name="thread_id"], input[name="thread"]').first().val(), 10);
				var boardUri = $(form).find('input[name="board"]').first().val();
				var watchLink = document.querySelector('.thread[data-thread-id="' + threadId + '"]');

				if (!threadId || !boardUri || !watchLink || watchLink.dataset.watched !== 'true') {
					return;
				}

				window.markWatchedThreadSeen(boardUri, threadId, post_response.id);
			};

			var syncThreadPageState = function(post_response) {
				if (!is_reply_form || !post_response) {
					return;
				}

				if (post_response.board_page_num) {
					$('#thread_stats_page').text(post_response.board_page_num);
				}

				if (post_response.board_page_path) {
					$('#thread-return, #thread-return-top').attr('href', post_response.board_page_path);
					$('#thread-refresh-target').attr('data-board-page-path', post_response.board_page_path);
				}

				if (post_response.board_page_num) {
					$('#thread-refresh-target').attr('data-board-page-num', post_response.board_page_num);
				}
			};

			var insertReplyMarkup = function(post_response) {
				if (!post_response || !post_response.html) {
					return $('div.post#reply_' + post_response.id).first();
				}

				var $reply = $('div.post#reply_' + post_response.id).first();
				if ($reply.length) {
					return $reply;
				}

				var $newReply = $($.parseHTML(post_response.html, document, true));
				var $container = $('#thread-refresh-target');

				if ($container.length) {
					$container.append($newReply);
				} else {
					var $thread = $('div.thread').first();
					if ($thread.length) {
						$thread.append($newReply);
					}
				}

				return $('div.post#reply_' + post_response.id).first();
			};


			var clearReplyFields = function() {
				$(form).find('input[name="subject"],input[name="file_url"],input[name="embed"],\
					textarea[name="body"],input[type="file"]').val('').change();
			};

			var updateProgress = function(e) {
				var percentage;
				if (e.position === undefined) { // Firefox
					percentage = Math.round(e.loaded * 100 / e.total);
				}
				else { // Chrome?
					percentage = Math.round(e.position * 100 / e.total);
				}
				$(form).find('input[type="submit"]').val(_('Posting... (#%)').replace('#', percentage));
			};

			$wrappedForm.data('ajax-posting', true);

			var submitAjax = function(retryOnCsrfFailure) {
				var formData = new FormData(form);
				formData.set('_csrf_token', currentCsrfToken());
				formData.set('json_response', '1');
				formData.set('post', submit_txt);

				$(document).trigger("ajax_before_post", [formData, form]);

				$.ajax({
					url: form.action,
					type: 'POST',
					xhr: function() {
						var xhr = $.ajaxSettings.xhr();
						if(xhr.upload) {
							xhr.upload.addEventListener('progress', updateProgress, false);
						}
						return xhr;
					},
					success: function(post_response) {
					if (post_response.error) {
						if (post_response.banned) {
							// You are banned. Must post the form normally so the user can see the ban message.
							do_not_ajax = true;
							$(form).find('input[type="submit"]').each(function() {
								var $replacement = $('<input type="hidden">');
								$replacement.attr('name', $(this).attr('name'));
								$replacement.val(submit_txt);
								$(this)
									.after($replacement)
									.replaceWith($('<input type="button">').val(submit_txt));
							});
							$(form).submit();
						} else {
							alert(post_response.error);
							resetSubmit();
						}
					} else if (post_response.redirect && post_response.id) {
						if (is_reply_form) {
							$submit.val(_('Posted...'));
							var $reply = insertReplyMarkup(post_response);

							if ($reply.length) {
								var anchor = document.getElementById(String(post_response.id)) || $reply[0];

								try {
									if (typeof window.syncBacklinksFromPost === 'function') {
										window.syncBacklinksFromPost($reply[0]);
									}
								} catch (e) {
									console.error(e);
								}

								clearReplyFields();
								resetSubmit();
								syncSeenForReply(post_response);
								syncThreadPageState(post_response);
								triggerAjaxAfterPost(post_response);

								try {
									if (window.EirinchanFrontend && typeof window.EirinchanFrontend.dispatchNewPost === 'function') {
										window.EirinchanFrontend.dispatchNewPost($reply[0]);
									} else {
										$(document).trigger('new_post', $reply[0]);
									}
								} catch (e) {
									console.error(e);
								}

								window.requestAnimationFrame(function() {
									window.requestAnimationFrame(function() {
										try {
											if (history && history.replaceState) {
												history.replaceState(null, document.title, window.location.pathname + window.location.search + '#' + post_response.id);
											} else {
												window.location.hash = post_response.id;
											}
										} catch (_e) {
											window.location.hash = post_response.id;
										}

										if (anchor.scrollIntoView) {
											anchor.scrollIntoView({block: "start"});
										} else {
											$(window).scrollTop($reply.offset().top);
										}

										try {
											highlightReply(post_response.id);
										} catch (e) {
											console.error(e);
										}

										setTimeout(function() { $(window).trigger("scroll"); }, 50);
									});
								});
							} else {
								clearReplyFields();
								resetSubmit();
								syncSeenForReply(post_response);
								syncThreadPageState(post_response);
								triggerAjaxAfterPost(post_response);
								try {
									if (history && history.replaceState) {
										history.replaceState(null, document.title, window.location.pathname + window.location.search + '#' + post_response.id);
									} else {
										window.location.hash = post_response.id;
									}
								} catch (_e) {
									window.location.hash = post_response.id;
								}
								alert(_('Reply posted. Refresh to see it.'));
							}
						} else {
							triggerAjaxAfterPost(post_response)
							document.location = post_response.redirect;
						}
					} else {
						alert(_('An unknown error occured when posting!'));
						resetSubmit();
					}
					},
					error: function(xhr, status, er) {
						console.log(xhr);

						if (retryOnCsrfFailure && xhr && xhr.status === 403) {
							refreshCsrfToken().done(function() {
								submitAjax(false);
							}).fail(function() {
								alert(_('Your tab is out of date. Refresh the page and try again.'));
								resetSubmit();
							});
							return;
						}

						var extracted = extractAjaxErrorMessage(xhr);
						if (extracted) {
							alert(extracted);
						} else if (xhr && xhr.status === 403) {
							alert(_('Your tab is out of date. Refresh the page and try again.'));
						} else {
							alert(_('The server took too long to submit your post. Your post was probably still submitted. If it wasn\'t, we might be experiencing issues right now -- please try your post again later.'));
						}
						resetSubmit();
					},
					data: formData,
					cache: false,
					contentType: false,
					processData: false,
					complete: function() {
						if ($submit.val() !== _('Posted...')) {
							$wrappedForm.removeData('ajax-posting');
						}
					}
				}, 'json');
			};

			submitAjax(true);
			
			$submit.val(_('Posting...'));
			$submit.attr('disabled', true);
			
			return false;
	};
	$(document).off('submit.ajax_post', 'form[data-post-form]');
	$(document).on('submit.ajax_post', 'form[data-post-form]', handle_form_submit);
});
/* End js/ajax.js */

/* Begin js/navarrows2.js */
if (active_page === 'thread' || active_page === 'index' || active_page === 'catalog' || active_page === 'ukko') {
document.addEventListener('DOMContentLoaded', function() {
        if (!(window.Options && Options.get_tab('general'))) {
                return;
        }

        var runtime = window.EirinchanRuntime || {};
        var readCookie = runtime.readCookie || function(name, fallback) {
                var match = document.cookie.match(new RegExp('(?:^|; )' + name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '=([^;]*)'));
                return match ? decodeURIComponent(match[1]) : fallback;
        };
        var writeCookie = runtime.writeCookie || function(name, value) {
                document.cookie = name + '=' + encodeURIComponent(value) + '; path=/; max-age=31536000; samesite=lax';
        };

        Options.extend_tab('general', '<label id="add-nav-arrows"><input type="checkbox">' + _('Display navigation arrows') + '</label>');

        var enabled = readCookie('navarrows', null);
        enabled = enabled !== 'false';
        $('#add-nav-arrows>input').prop('checked', enabled);

        $('#add-nav-arrows>input').on('click', function() {
                var value = $('#add-nav-arrows>input').is(':checked') ? 'true' : 'false';
                writeCookie('navarrows', value, { path: '/', maxAge: 31536000, sameSite: 'lax' });
                location.reload();
        });
})};
/* End js/navarrows2.js */

/* Begin js/file-selector.js */
/*
 * file-selector.js - Add support for drag and drop file selection, and paste from clipboard on supported browsers.
 *
 * Usage:
 *   $config['additional_javascript'][] = 'js/jquery.min.js';
 *   $config['additional_javascript'][] = 'js/ajax.js';
 *   $config['additional_javascript'][] = 'js/file-selector.js';
 */
function init_file_selector(max_images, root) {
  if (/iPad|iPhone|iPod/.test(navigator.userAgent)) {
    return;
  }

  if (!(window.URL.createObjectURL && window.File)) {
    return;
  }

  if (typeof max_images === 'undefined') {
    max_images = 1;
  }

  var $root = root ? $(root) : $('form[name="post"]').first();
  if (!$root.length || $root.data('file-selector-initialized')) {
    return;
  }

  var $uploadCell = $root.find('#upload td, [data-upload-row] td').first();
  var $fileInput = $root.find('#upload_file, [data-upload-file]').first();
  var $dropzoneWrap = $uploadCell.find('.dropzone-wrap').first();

  if (!$uploadCell.length || !$fileInput.length || !$dropzoneWrap.length) {
    return;
  }

  var files = [];
  var selectorNamespace = '.file_selector_' + ($root.attr('id') || Math.floor(Math.random() * 1000000));
  var $dropzone = $dropzoneWrap.find('.dropzone').first();
  var $thumbs = $dropzoneWrap.find('.file-thumbs').first();

  if (!$dropzone.length || !$thumbs.length) {
    return;
  }

  $dropzoneWrap.css('user-select', 'none');
  $root.data('file-selector-initialized', true);

  function thumbContainerCount() {
    return $root.find('.tmb-container').length;
  }

  function updateArrowVisibility() {
    $root.find('.tmb-container').each(function(index, element) {
      var $el = $(element);
      $el.find('.move-up-btn').toggle(index !== 0);
      $el.find('.move-down-btn').toggle(index !== thumbContainerCount() - 1);
    });
  }

  function removeFile(file) {
    files.splice(files.indexOf(file), 1);
  }

  function getThumbElement(file) {
    return $root.find('.tmb-container').filter(function() {
      return $(this).data('file-ref') === file;
    });
  }

  function addThumb(file) {
    var fileName = (file.name.length < 24) ? file.name : file.name.substr(0, 22) + '…';
    var fileType = file.type.split('/')[0];
    var fileExt = (file.type.split('/')[1] || file.name.split('.').pop() || '').toUpperCase();

    var $container = $('<div>')
      .addClass('tmb-container')
      .data('file-ref', file)
      .append(
        $('<div>').addClass('tmb-controls').append(
          $('<div>').addClass('remove-btn').text('✖'),
          $('<div>').addClass('move-up-btn').text('⬆'),
          $('<div>').addClass('move-down-btn').text('⬇'),
          $('<div>').addClass('strip-fn-btn').text('strip filename')
        ),
        $('<div>').addClass('file-tmb'),
        $('<div>').addClass('tmb-filename').text(fileName)
      )
      .appendTo($thumbs);

    var $fileThumb = $container.find('.file-tmb');
    if (fileType === 'image') {
      var objURL = window.URL.createObjectURL(file);
      $fileThumb.css('background-image', 'url(' + objURL + ')');
    } else {
      $('<span>').text(fileExt).appendTo($fileThumb.empty());
    }

    updateArrowVisibility();
  }

  function addFile(file) {
    if (files.length === max_images) {
      return;
    }

    files.push(file);
    addThumb(file);
  }

  $root.on('click', '.move-up-btn', function(e) {
    e.stopPropagation();
    var $current = $(this).closest('.tmb-container');
    var file = $current.data('file-ref');
    var index = files.indexOf(file);

    if (index > 0) {
      var tmp = files[index - 1];
      files[index - 1] = files[index];
      files[index] = tmp;
      $current.insertBefore($current.prev());
      updateArrowVisibility();
    }
  });

  $root.on('click', '.move-down-btn', function(e) {
    e.stopPropagation();
    var $current = $(this).closest('.tmb-container');
    var file = $current.data('file-ref');
    var index = files.indexOf(file);

    if (index < files.length - 1) {
      var tmp = files[index + 1];
      files[index + 1] = files[index];
      files[index] = tmp;
      $current.insertAfter($current.next());
      updateArrowVisibility();
    }
  });

  $(document).on('ajax_before_post' + selectorNamespace, function(e, formData, form) {
    if (form !== $root[0]) {
      return;
    }

    if (max_images > 1) {
      for (var i = 0; i < max_images; i++) {
        if (typeof files[i] === 'undefined') break;
        formData.append('files[]', files[i]);
      }
      return;
    }

    for (var i = 0; i < max_images; i++) {
      if (typeof files[i] === 'undefined') break;
      formData.append('file', files[i]);
    }
  });

  $(document).on('ajax_after_post' + selectorNamespace, function(e, response, form) {
    if (form !== $root[0]) {
      return;
    }

    files = [];
    $root.find('.file-thumbs').empty();
  });

  $(document).on('click' + selectorNamespace, '.strip-fn-btn', function(e) {
    if (!$.contains($root[0], this)) {
      return;
    }

    e.stopPropagation();
    var $container = $(this).closest('.tmb-container');
    var index = $container.parent().children('.tmb-container').index($container);
    var file = files[index] || $container.data('file-ref');

    if (!file || !file.name) {
      return;
    }

    var extension = file.name.indexOf('.') !== -1 ? file.name.split('.').pop() : '';
    var newName = extension ? (Date.now() + '.' + extension) : String(Date.now());
    var newFile = new File([file.slice(0, file.size, file.type)], newName, { type: file.type });

    files[index] = newFile;
    $container.data('file-ref', newFile);
    $container.find('.tmb-filename').text(newName);
  });

  var dragCounter = 0;
  var dropTarget = $root[0];

  function cancelDragEvent(e) {
    e.stopPropagation();
    e.preventDefault();
  }

  function onDragEnter(e) {
    cancelDragEvent(e);

    if (dragCounter === 0) {
      $dropzone.addClass('dragover');
    }
    dragCounter++;
  }

  function onDragLeave(e) {
    cancelDragEvent(e);
    dragCounter--;
    if (dragCounter <= 0) {
      dragCounter = 0;
      $dropzone.removeClass('dragover');
    }
  }

  function onDrop(e) {
    cancelDragEvent(e);
    $dropzone.removeClass('dragover');
    dragCounter = 0;

    var fileList = e.dataTransfer.files;
    for (var i = 0; i < fileList.length; i++) {
      addFile(fileList[i]);
    }
  }

  ['dragenter', 'dragover', 'dragleave', 'drop'].forEach(function(type) {
    dropTarget.addEventListener(type, cancelDragEvent, true);
  });
  dropTarget.addEventListener('dragenter', onDragEnter, true);
  dropTarget.addEventListener('dragleave', onDragLeave, true);
  dropTarget.addEventListener('drop', onDrop, true);

  $root.on('click', '.remove-btn', function(e) {
    e.stopPropagation();
    var file = $(e.target).closest('.tmb-container').data('file-ref');
    getThumbElement(file).remove();
    removeFile(file);
    updateArrowVisibility();
  });

  $dropzone.on('keypress click', function(e) {
    if ((e.which !== 1 || e.target.className !== 'file-hint') && e.which !== 13) {
      return;
    }

    e.stopPropagation();

    var $selector = $('<input type="file" multiple>');

    $selector.on('change', function() {
      if (this.files.length > 0) {
        for (var i = 0; i < this.files.length; i++) {
          addFile(this.files[i]);
        }
      }
      $(this).remove();
    });

    $selector.trigger('click');
  });

  $(document).on('paste' + selectorNamespace, function(e) {
    if (!$.contains($root[0], document.activeElement) && document.activeElement !== $root[0]) {
      return;
    }

    var clipboard = e.originalEvent.clipboardData;
    if (typeof clipboard.items === 'undefined' || clipboard.items.length === 0) {
      return;
    }

    for (var i = 0; i < clipboard.items.length; i++) {
      if (clipboard.items[i].kind !== 'file') {
        continue;
      }

      var file = new File([clipboard.items[i].getAsFile()], 'file.png', { type: 'image/png' });
      addFile(file);
    }
  });
}

$(function() {
  $('form[data-post-form]').each(function() {
    var maxImages = parseInt($(this).attr('data-max-images') || '1', 10);
    if (isNaN(maxImages) || maxImages < 1) {
      maxImages = 1;
    }

    init_file_selector(maxImages, this);
  });
});
/* End js/file-selector.js */

/* Begin js/upload-selection.js */
/*
 * upload-selection.js - makes upload fields in post form more compact
 * https://github.com/vichan-devel/Tinyboard/blob/master/js/upload-selection.js
 *
 * Released under the MIT license
 * Copyright (c) 2014 Marcin Łabanowski <marcin@6irc.net>
 *
 * Usage:
 *   $config['additional_javascript'][] = 'js/jquery.min.js';
 *   //$config['additional_javascript'][] = 'js/wpaint.js';
 *   $config['additional_javascript'][] = 'js/upload-selection.js';
 *                                                  
 */

$(function(){
  var enabled_url = $("#upload_url").length > 0;
  var enabled_embed = $("#upload_embed").length > 0;
  var enabled_oekaki = typeof window.oekaki != "undefined";

  var disable_all = function() {
    $("#upload").hide();
    $("[id^=upload_file]").hide();
    $(".file_separator").hide();
    $("#upload_url").hide();
    $("#upload_embed").hide();
    $(".add_image").hide();
    $(".dropzone-wrap").hide();

    if (enabled_oekaki) {
      if (window.oekaki.initialized) {
        window.oekaki.deinit();
      }
    }
  };

  enable_file = function() {
    disable_all();
    $("#upload").show();
    $(".dropzone-wrap").show();
    $(".file_separator").show();
    $("[id^=upload_file]").show();
    $(".add_image").show();
    if (enabled_embed) {
      $("#upload_embed").show();
    }
  };

  enable_url = function() {
    disable_all();
    $("#upload").show();
    $("#upload_url").show();

    $('label[for="file_url"]').html(_("URL"));
  };

  enable_embed = function() {
    enable_file();
    $("#upload_embed").show();
    $("#upload_embed").find('input[name=\"embed\"]').focus();
  };

  enable_oekaki = function() {
    disable_all();

    window.oekaki.init();
  };

  if (enabled_oekaki) {
    $("#confirm_oekaki_label").hide();
  }

  // The default file-upload state is rendered server-side.
  // Only keep the mode-switch helpers for explicit interactions.
});
/* End js/upload-selection.js */

/* Begin js/expand.js */
/*
 * expand.js
 * https://github.com/savetheinternet/Tinyboard/blob/master/js/expand.js
 *
 * Released under the MIT license
 * Copyright (c) 2012-2013 Michael Save <savetheinternet@tinyboard.org>
 * Copyright (c) 2013 Czterooki <czterooki1337@gmail.com>
 * Copyright (c) 2013-2014 Marcin Łabanowski <marcin@6irc.net>
 *
 * Usage:
 *   $config['additional_javascript'][] = 'js/jquery.min.js';
 *   $config['additional_javascript'][] = 'js/expand.js';
 *
 */

window.EirinchanInitExpand = function(root) {
	var $root = root ? $(root) : $(document);
	var $omitted = $root.is('span.omitted') ? $root : $root.find('span.omitted');
	$omitted = $omitted.filter(function() {
		return $(this).closest('[id^="thread_"]').length > 0 && !$(this).hasClass('hide-expanded');
	});

	if($omitted.length == 0)
		return;

	var do_expand = function() {
		if ($(this).find('a').length) {
			return;
		}

		$(this)
			.html($(this).text().replace(_("Click reply to view."), '<a href="#">'+_("Click to expand")+'</a>.'))
			.find('a').click(window.expand_fun = function(e) {
				e.preventDefault();
				var thread = $(this).parents('[id^="thread_"]');
				var id = thread.attr('id').replace(/^thread_/, '');
				$.ajax({
					url: thread.find('p.intro a.post_no:first').attr('href'),
					context: document.body,
					success: function(data) {
						var last_expanded = false;
						$(data).find('div.post.reply').each(function() {
							thread.find('div.hidden').remove();
							var post_in_doc = thread.find('#' + $(this).attr('id'));
							if(post_in_doc.length == 0) {
								if(last_expanded) {
									$(this).addClass('expanded').insertAfter(last_expanded).before('<br class="expanded">');
								} else {
									$(this).addClass('expanded').insertAfter(thread.find('div.post:first')).after('<br class="expanded">');
								}
								last_expanded = $(this);
								$(document).trigger('new_post', this);
							} else {
								last_expanded = post_in_doc;
							}
						});
						

						thread.find("span.omitted").css('display', 'none');

						var insertionPoint = thread.children('span.omitted').last();
						if (!insertionPoint.length) {
							insertionPoint = thread.find('.op div.body').last();
						}

						$('<span class="omitted hide-expanded"><a href="#">' + _('Hide expanded replies') + '</a>.</span>')
							.insertAfter(insertionPoint)
							.click(function(e) {
								e.preventDefault();
								thread.find('.expanded').remove();
								thread.find(".omitted:not(.hide-expanded)").css('display', '');
								thread.find(".hide-expanded").remove();
							});
					}
				});
			});
	}

	$omitted.each(do_expand);
};

$(document).ready(function(){
	window.EirinchanInitExpand(document);

	$(document).on("new_post", function(e, post) {
		if (!$(post).hasClass("reply")) {
			window.EirinchanInitExpand(post);
		}
	});
});
/* End js/expand.js */

