$(document).ready(function(){
	var csrfToken = function() {
		var token = $('input[name=_csrf_token]:first').val();
		if (token)
			return token;

		return $('meta[name="csrf-token"]').attr('content') || '';
	};

	var boardUri = function($checkbox) {
		var board = $('input[name=board]:first').val();
		if (board)
			return board;

		var container = $checkbox.closest('[data-board],[data-board-uri]');
		return container.attr('data-board') || container.attr('data-board-uri') || '';
	};

	var postAction = function() {
		return $('form[name="post"]:first').attr('action') || '/post.php';
	};

	var open_form = function() {
		var $checkbox = $(this);
		var thread = $checkbox.parent().parent().hasClass('op');
		var id = $(this).attr('name').match(/^delete_(\d+)$/)[1];
		var submitButton;
		
		if(this.checked) {
			var board = boardUri($checkbox);
			var post_form = $('<form class="post-actions" method="post" style="margin:10px 0 0 0">' +
				'<div style="text-align:right">' +
					(!thread ? '<hr>' : '') +
					
					'<input type="hidden" name="delete_' + id + '">' +
					
					'<label for="password_' + id + '">'+_("Password")+'</label>: ' +
					'<input id="password_' + id + '" type="password" name="password" size="11" maxlength="18" autocomplete="off">' +
					'<input title="'+_('Delete file only')+'" type="checkbox" name="file" id="delete_file_' + id + '">' +
						'<label for="delete_file_' + id + '">'+_('File')+'</label>' +
					' <input type="submit" name="delete" value="'+_('Delete')+'">' +
				
					'<br>' +
				
					'<label for="reason_' + id + '">'+_('Reason')+'</label>: ' +
					'<input id="reason_' + id + '" type="text" name="reason" size="20" maxlength="100">' +
					' <input type="submit" name="report" value="'+_('Report')+'">' +
				'</div>' +
			'</form>');
			post_form
				.attr('action', postAction())
				.append($('<input type="hidden" name="board">').val(board))
				.append($('<input type="hidden" name="_csrf_token">').val(csrfToken()))
				.find('input:not([type="checkbox"]):not([type="submit"]):not([type="hidden"])').keypress(function(e) {
					if(e.which == 13) {
						e.preventDefault();
						if($(this).attr('name') == 'password')  {
							post_form.find('input[name=delete]').click();
						} else if($(this).attr('name') == 'reason')  {
							post_form.find('input[name=report]').click();
						}
						
						return false;
					}
					
					return true;
				});
			
			post_form.find('input[type="password"]').val(localStorage.password);
			
			if(thread) {
				post_form.prependTo($(this).parent().parent().find('div.body'));
			} else {
				post_form.appendTo($(this).parent().parent());
				//post_form.insertBefore($(this));
			}
			
			$(window).trigger('quick-post-controls', post_form);
		} else {
			var elm = $(this).parent().parent().find('form');
			
			if(elm.attr('class') == 'post-actions')
				elm.remove();
		}
	};
	
	var init_qpc = function() {
		$(this).change(open_form);
		if(this.checked)
			$(this).trigger('change');
	};

	$('div.post input[type=checkbox].delete').each(init_qpc);

	$(document).on('new_post', function(e, post) {
		$(post).find('input[type=checkbox].delete').each(init_qpc);
	});
});
/* End js/quick-post-controls.js */

/* Begin js/webm-settings.js */
/* This file is dedicated to the public domain; you may do as you wish with it. */

if (typeof _ == 'undefined') {
  var _ = function(a) { return a; };
}

// Default settings
var defaultSettings = {
    "videoexpand": true,
    "videohover": false,
    "videovolume": 0.4
};

// Non-persistent settings for when localStorage is absent/disabled
var tempSettings = {};

// Scripts obtain settings by calling this function
function setting(name) {
    if (localStorage) {
        if (localStorage[name] === undefined) return defaultSettings[name];
        return JSON.parse(localStorage[name]);
    } else {
        if (tempSettings[name] === undefined) return defaultSettings[name];
        return tempSettings[name];
    }
}

// Settings should be changed with this function
function changeSetting(name, value) {
    if (localStorage) {
        localStorage[name] = JSON.stringify(value);
    } else {
        tempSettings[name] = value;
    }
}

// Create settings menu
var settingsMenu = document.createElement("div");
var prefix = "", suffix = "", style = "";
if (window.Options) {
  var tab = Options.add_tab("webm", "video-camera", _("WebM"));
  $(settingsMenu).appendTo(tab.content);
}
else {
  prefix = '<a class="unimportant" href="#">'+_('WebM Settings')+'</a>';
  settingsMenu.style.textAlign = "right";
  settingsMenu.style.background = "inherit";
  suffix = '</div>';
  style = 'display: none; text-align: left; position: absolute; right: 1em; margin-left: -999em; margin-top: -1px; padding-top: 1px; background: inherit;';
}

settingsMenu.innerHTML = prefix
    + '<div style="'+style+'">'
    + '<label><input type="checkbox" name="videoexpand">'+_('Expand videos inline')+'</label><br>'
    + '<label><input type="checkbox" name="videohover">'+_('Play videos on hover')+'</label><br>'
    + '<label><input type="range" name="videovolume" min="0" max="1" step="0.01" style="width: 4em; height: 1ex; vertical-align: middle; margin: 0px;">'+_('Default volume')+'</label><br>'
    + suffix;

function refreshSettings() {
    var settingsItems = settingsMenu.getElementsByTagName("input");
    for (var i = 0; i < settingsItems.length; i++) {
        var control = settingsItems[i];
        if (control.type == "checkbox") {
            control.checked = setting(control.name);
        } else if (control.type == "range") {
            control.value = setting(control.name);
        }
    }
}

function setUpControl(control) {
    if (control.addEventListener) control.addEventListener("change", function(e) {
        if (control.type == "checkbox") {
            changeSetting(control.name, control.checked);
        } else if (control.type == "range") {
            changeSetting(control.name, control.value);
        }
    }, false);
}

refreshSettings();
var settingsItems = settingsMenu.getElementsByTagName("input");
for (var i = 0; i < settingsItems.length; i++) {
    setUpControl(settingsItems[i]);
}

if (settingsMenu.addEventListener && !window.Options) {
    settingsMenu.addEventListener("click", function(e) {
        if (e.target && e.target.tagName === "A") {
            e.preventDefault();
        }
    }, false);
    settingsMenu.addEventListener("mouseover", function(e) {
        refreshSettings();
        settingsMenu.getElementsByTagName("a")[0].style.fontWeight = "bold";
        settingsMenu.getElementsByTagName("div")[0].style.display = "block";
    }, false);
    settingsMenu.addEventListener("mouseout", function(e) {
        settingsMenu.getElementsByTagName("a")[0].style.fontWeight = "normal";
        settingsMenu.getElementsByTagName("div")[0].style.display = "none";
    }, false);
}
/* End js/webm-settings.js */

/* Begin js/expand-video.js */
/* This file is dedicated to the public domain; you may do as you wish with it. */
/* Note: This code expects the global variable configRoot to be set. */

if (typeof _ == 'undefined') {
	var _ = function(a) {
		return a;
	};
}

function setupVideo(thumb, url) {
	if (thumb.videoAlreadySetUp) {
		return;
	}
	thumb.videoAlreadySetUp = true;

	let video = null;
	let videoContainer, videoHide;
	let expanded = false;
	let hovering = false;
	let loop = true;
	let fileInfo = thumb.parentNode.querySelector(".fileinfo");
	let loopControls = [];
	let mouseDown = false;

	function ensureLoopControls() {
		if (!fileInfo || fileInfo.querySelector("[data-video-loop-controls]")) {
			return;
		}

		let controls = document.createElement("span");
		controls.className = "video-loop-controls";
		controls.setAttribute("data-video-loop-controls", "");

		let once = document.createElement("span");
		once.className = "video-loop-control";
		once.setAttribute("data-video-loop-mode", "once");
		once.textContent = "[play once]";

		let loopControl = document.createElement("span");
		loopControl.className = "video-loop-control active";
		loopControl.setAttribute("data-video-loop-mode", "loop");
		loopControl.textContent = "[loop]";

		controls.appendChild(document.createTextNode(" "));
		controls.appendChild(once);
		controls.appendChild(document.createTextNode(" "));
		controls.appendChild(loopControl);
		fileInfo.appendChild(controls);
	}

	function unexpand() {
		if (expanded) {
			expanded = false;
			if (video.pause) {
				video.pause();
			}
			videoContainer.style.display = "none";
			thumb.style.display = "inline";
			video.style.maxWidth = "inherit";
			video.style.maxHeight = "inherit";
		}
	}

	function unhover() {
		if (hovering) {
			hovering = false;
			if (video.pause) {
				video.pause();
			}
			videoContainer.style.display = "none";
			video.style.maxWidth = "inherit";
			video.style.maxHeight = "inherit";
		}
	}

	// Create video element if does not exist yet
	function getVideo() {
		if (video == null) {
			video = document.createElement("video");
			video.src = url;
			video.loop = loop;
			video.preload = "metadata";
			video.setAttribute("playsinline", "");
			video.setAttribute("webkit-playsinline", "");
			video.innerText = _("Your browser does not support HTML5 video.");

			videoHide = document.createElement("img");
			videoHide.src = configRoot + "static/collapse.gif";
			videoHide.alt = "[ - ]";
			videoHide.title = "Collapse video";
			videoHide.style.marginLeft = "-15px";
			videoHide.style.cssFloat = "left";
			videoHide.addEventListener("click", unexpand, false);

			videoContainer = document.createElement("div");
			videoContainer.style.paddingLeft = "15px";
			videoContainer.style.display = "none";
			videoContainer.appendChild(videoHide);
			videoContainer.appendChild(video);
			thumb.parentNode.insertBefore(videoContainer, thumb.nextSibling);

			// Keep plain clicks on the player from leaking into surrounding UI.
			// Do not trap touch/pointer release events here; native mobile seek controls
			// need those to commit the new playhead position.
			["click"].forEach(function(eventName) {
				video.addEventListener(eventName, function(e) {
					e.stopPropagation();
				}, false);
			});

			// Dragging to the left collapses the video
			video.addEventListener("mousedown", function(e) {
				if (e.button == 0) mouseDown = true;
			}, false);
			video.addEventListener("mouseup", function(e) {
				if (e.button == 0) mouseDown = false;
			}, false);
			video.addEventListener("mouseenter", function(e) {
				mouseDown = false;
			}, false);
			video.addEventListener("mouseout", function(e) {
				if (mouseDown && e.clientX - video.getBoundingClientRect().left <= 0) {
					unexpand();
				}
				mouseDown = false;
			}, false);
		}
	}

	function setVolume() {
		const volume = setting("videovolume");
		video.volume = volume;
		video.muted = (volume === 0);
	}

	// Clicking on thumbnail expands video
	thumb.addEventListener("click", function(e) {
		if (setting("videoexpand") && !e.shiftKey && !e.ctrlKey && !e.altKey && !e.metaKey) {
			getVideo();
			expanded = true;
			hovering = false;

			video.style.position = "static";
			video.style.pointerEvents = "inherit";
			video.style.display = "inline";
			videoHide.style.display = "inline";
			videoContainer.style.display = "block";
			videoContainer.style.position = "static";
			video.parentNode.parentNode.removeAttribute('style');
			thumb.style.display = "none";

			setVolume();
			video.controls = true;
			if (video.readyState == 0) {
				video.addEventListener("loadedmetadata", expand2, false);
			} else {
				setTimeout(expand2, 0);
			}
			let promise = video.play();
			if (promise !== undefined) {
				promise.then(_ => {
				}).catch(_ => {
					video.muted = true;
					video.play();
				});
			}
			e.preventDefault();
		}
	}, false);

	function expand2() {
		video.style.maxWidth = "100%";
		video.style.maxHeight = window.innerHeight + "px";
		var bottom = video.getBoundingClientRect().bottom;
		if (bottom > window.innerHeight) {
			window.scrollBy(0, bottom - window.innerHeight);
		}
		// work around Firefox volume control bug
		video.volume = Math.max(setting("videovolume") - 0.001, 0);
		video.volume = setting("videovolume");
	}

	// Hovering over thumbnail displays video
	thumb.addEventListener("mouseover", function(e) {
		if (setting("videohover")) {
			getVideo();
			expanded = false;
			hovering = true;

			let docRight = document.documentElement.getBoundingClientRect().right;
			let thumbRight = thumb.querySelector("img, video").getBoundingClientRect().right;
			let maxWidth = docRight - thumbRight - 20;
			if (maxWidth < 250) {
				maxWidth = 250;
			}

			video.style.position = "fixed";
			video.style.right = "0px";
			video.style.top = "0px";
			docRight = document.documentElement.getBoundingClientRect().right;
			thumbRight = thumb.querySelector("img, video").getBoundingClientRect().right;
			video.style.maxWidth = maxWidth + "px";
			video.style.maxHeight = "100%";
			video.style.pointerEvents = "none";

			video.style.display = "inline";
			videoHide.style.display = "none";
			videoContainer.style.display = "inline";
			videoContainer.style.position = "fixed";

			setVolume();
			video.controls = false;
			let promise = video.play();
			if (promise !== undefined) {
				promise.then(_ => {
				}).catch(_ => {
					video.muted = true;
					video.play();
				});
			}
		}
	}, false);

	thumb.addEventListener("mouseout", unhover, false);

	// Scroll wheel on thumbnail adjusts default volume
	thumb.addEventListener("wheel", function(e) {
		if (setting("videohover")) {
			var volume = setting("videovolume");
			if (e.deltaY > 0) {
				volume -= 0.1;
			}
			if (e.deltaY < 0) {
				volume += 0.1;
			}
			if (volume < 0) {
				volume = 0;
			}
			if (volume > 1) {
				volume = 1;
			}
			if (video != null) {
				video.muted = (volume == 0);
				video.volume = volume;
			}
			changeSetting("videovolume", volume);
			e.preventDefault();
		}
	}, false);

	// [play once] vs [loop] controls
	function updateLoopHref(modeIndex) {
		let href = thumb.getAttribute("href") || url;
		let separator = href.indexOf("?") === -1 ? "?" : "&";
		if (/([\?&])loop=\d+/.test(href)) {
			href = href.replace(/([\?&])loop=\d+/, "$1loop=" + modeIndex);
		} else {
			href += separator + "loop=" + modeIndex;
		}
		thumb.setAttribute("href", href);
	}

	function updateLoopControlClasses(activeControl) {
		for (let i = 0; i < loopControls.length; i++) {
			loopControls[i].classList.toggle("active", loopControls[i] === activeControl);
		}
	}

	function setupLoopControl(control, modeIndex) {
		control.addEventListener("click", function(e) {
			loop = (modeIndex != 0);
			updateLoopHref(modeIndex);
			if (video != null) {
				video.loop = loop;
				if (loop && video.currentTime >= video.duration) {
					video.currentTime = 0;
				}
			}
			updateLoopControlClasses(control);
			e.preventDefault();
			e.stopPropagation();
		}, false);
	}

	if (fileInfo) {
		ensureLoopControls();
		loopControls = Array.prototype.slice.call(fileInfo.querySelectorAll("[data-video-loop-mode]"));
		if (loopControls.length === 2) {
			for (let i = 0; i < loopControls.length; i++) {
				setupLoopControl(loopControls[i], loopControls[i].getAttribute("data-video-loop-mode") === "once" ? 0 : 1);
			}
			updateLoopControlClasses(fileInfo.querySelector("[data-video-loop-mode=\"loop\"]") || loopControls[1]);
		}
	}
}

function setupVideosIn(element) {
	let thumbs = element.querySelectorAll("a.file");
	for (let i = 0; i < thumbs.length; i++) {
		if (/\.webm$|\.mp4$|\.mp3$|\.wav$|\.mov$|\.flac$/i.test(thumbs[i].pathname)) {
			setupVideo(thumbs[i], thumbs[i].href);
		} else {
			let m = thumbs[i].search.match(/\bv=([^&]*)/);
			if (m != null) {
				let url = decodeURIComponent(m[1]);
				if (/\.webm$|\.mp4$|\.mp3$|\.wav$|\.mov$|\.flac$/i.test(url)) {
					setupVideo(thumbs[i], url);
				}
			}
		}
	}
}

onReady(function(){
	// Insert menu from settings.js
	if (typeof settingsMenu != "undefined" && typeof Options == "undefined") {
		document.body.insertBefore(settingsMenu, document.getElementsByTagName("hr")[0]);
	}

	// Setup Javascript events for videos in document now
	setupVideosIn(document);

	// Setup Javascript events for videos added by updater
	if (window.MutationObserver) {
		let observer = new MutationObserver(function(mutations) {
			for (let i = 0; i < mutations.length; i++) {
				let additions = mutations[i].addedNodes;
				if (additions == null) {
					continue;
				}
				for (let j = 0; j < additions.length; j++) {
					let node = additions[j];
					if (node.nodeType == 1) {
						setupVideosIn(node);
					}
				}
			}
		});
		observer.observe(document.body, {childList: true, subtree: true});
	}
});
/* End js/expand-video.js */
